/**
 * Metadata bit-mask enum for the `clang` option table.
 *
 * The values in this enum are exposed through `OptionInfo.flags`.
 *
 * @example
 * ```typescript
 * import { option } from "catter";
 * import { option_get_info } from "catter-c";
 *
 * const info = option_get_info("clang", option.ClangID.ID_UNKNOWN);
 * const isSet = (info.flags & option.ClangFlag.HelpHidden) !== 0;
 * ```
 */
export enum ClangFlag {
  None = 0,
  HelpHidden = 1,
  RenderAsInput = 2,
  RenderJoined = 4,
  Ignored = 16,
  LinkOption = 32,
  LinkerInput = 64,
  NoArgumentUnused = 128,
  NoXarchOption = 256,
  TargetSpecific = 512,
  Unsupported = 1024,
}

/**
 * Visibility bit-mask enum for the `clang` option table.
 *
 * The values in this enum are exposed through `OptionInfo.visibility`.
 *
 * @example
 * ```typescript
 * import { option } from "catter";
 * import { option_get_info } from "catter-c";
 *
 * const info = option_get_info("clang", option.ClangID.ID_UNKNOWN);
 * const isVisible = (info.visibility & option.ClangVisibility.DefaultVis) !== 0;
 * ```
 */
export enum ClangVisibility {
  None = 0,
  DefaultVis = 1,
  CLOption = 2,
  CC1Option = 4,
  CC1AsOption = 8,
  FC1Option = 16,
  DXCOption = 32,
  FlangOption = 64,
}

/**
 * Driver-class bit-mask enum for the `clang` option table.
 *
 * This mirrors the class bits associated with generated driver options.
 *
 * @example
 * ```typescript
 * import { option } from "catter";
 * import { option_get_info } from "catter-c";
 *
 * const info = option_get_info("clang", option.ClangID.ID_UNKNOWN);
 * const matchesClass = (info.visibility & option.ClangDriverClass.DefaultVis) !== 0;
 * ```
 */
export enum ClangDriverClass {
  None = 0,
  DefaultVis = 1,
  CLOption = 2,
  CC1Option = 4,
  CC1AsOption = 8,
  FC1Option = 16,
  DXCOption = 32,
  FlangOption = 64,
}
